// NEWS2 Calculator - National Early Warning Score 2
// Accepts vital signs as JSON object or string
const raw = $fromAI('vital_signs', 'JSON object with keys: rr (resp rate), spo2 (%), sbp (systolic mmHg as string e.g. "120/80"), hr (heart rate), temp (celsius), gcs (15=normal), on_oxygen (bool)', 'json');

let params;
try {
  params = (typeof raw === 'string') ? JSON.parse(raw) : raw;
} catch(e) { return JSON.stringify({error: 'Invalid input: ' + e.message}); }

let score = 0;
const notes = [];

const rr   = parseFloat(params.rr);
const spo2 = parseFloat(params.spo2);
const sbp  = parseFloat((params.sbp || '').toString().split('/')[0]);
const hr   = parseFloat(params.hr);
const temp = parseFloat(params.temp);
const gcs  = parseFloat(params.gcs ?? 15);
const o2   = params.on_oxygen === true || params.on_oxygen === 'true';

if (!isNaN(rr)) {
  if (rr <= 8)       { score += 3; notes.push('RR<=8: +3'); }
  else if (rr <= 11) { score += 1; notes.push('RR 9-11: +1'); }
  else if (rr <= 20) { notes.push('RR 12-20: +0'); }
  else if (rr <= 24) { score += 2; notes.push('RR 21-24: +2'); }
  else               { score += 3; notes.push('RR>=25: +3'); }
}

if (!isNaN(spo2)) {
  if (spo2 <= 91)      { score += 3; notes.push('SpO2<=91: +3'); }
  else if (spo2 <= 93) { score += 2; notes.push('SpO2 92-93: +2'); }
  else if (spo2 <= 95) { score += 1; notes.push('SpO2 94-95: +1'); }
  else                 { notes.push('SpO2>=96: +0'); }
}

if (o2) { score += 2; notes.push('On O2: +2'); }

if (!isNaN(sbp)) {
  if (sbp <= 90)        { score += 3; notes.push('SBP<=90: +3'); }
  else if (sbp <= 100)  { score += 2; notes.push('SBP 91-100: +2'); }
  else if (sbp <= 110)  { score += 1; notes.push('SBP 101-110: +1'); }
  else if (sbp <= 219)  { notes.push('SBP 111-219: +0'); }
  else                  { score += 3; notes.push('SBP>=220: +3'); }
}

if (!isNaN(hr)) {
  if (hr <= 40)      { score += 3; notes.push('HR<=40: +3'); }
  else if (hr <= 50) { score += 1; notes.push('HR 41-50: +1'); }
  else if (hr <= 90) { notes.push('HR 51-90: +0'); }
  else if (hr <= 110){ score += 1; notes.push('HR 91-110: +1'); }
  else if (hr <= 130){ score += 2; notes.push('HR 111-130: +2'); }
  else               { score += 3; notes.push('HR>=131: +3'); }
}

if (!isNaN(temp)) {
  if (temp <= 35.0)      { score += 3; notes.push('Temp<=35: +3'); }
  else if (temp <= 36.0) { score += 1; notes.push('Temp 35.1-36: +1'); }
  else if (temp <= 38.0) { notes.push('Temp 36.1-38: +0'); }
  else if (temp <= 39.0) { score += 1; notes.push('Temp 38.1-39: +1'); }
  else                   { score += 2; notes.push('Temp>=39.1: +2'); }
}

if (!isNaN(gcs) && gcs < 15) { score += 3; notes.push('GCS<15: +3'); }

const risk = score >= 7 ? 'HIGH - Continuous monitoring' :
             score >= 5 ? 'MEDIUM-HIGH - Urgent review' :
             score >= 3 ? 'MEDIUM - Increased monitoring' : 'LOW';

return JSON.stringify({ NEWS2_score: score, risk, breakdown: notes, input: params });

const p = $fromAI(
  'heart_params',
  'Return JSON with keys: history ("highly"|"moderately"|"slightly"), ecg ("normal"|"non-specific"|"lbbb_stemi"), age (number), risk_factors (number), troponin ("normal"|"1_3x"|"gt3x")',
  'json'
);

const H = p.history === 'highly' ? 2 : p.history === 'moderately' ? 1 : 0;
const E = p.ecg === 'lbbb_stemi' ? 2 : p.ecg === 'non-specific' ? 1 : 0;
const A = p.age >= 65 ? 2 : p.age >= 45 ? 1 : 0;
const R = p.risk_factors >= 3 ? 2 : p.risk_factors >= 1 ? 1 : 0;
const T = p.troponin === 'gt3x' ? 2 : p.troponin === '1_3x' ? 1 : 0;

const score = H + E + A + R + T;

const risk =
  score >= 7 ? 'HIGH (>50% MACE at 30d) — consider admit + early invasive' :
  score >= 4 ? 'MODERATE (12–17% MACE) — observe, serial troponins' :
  'LOW (<2% MACE) — consider early discharge';

return JSON.stringify({
  heart_score: score,
  breakdown: { H, E, A, R, T },
  mace_risk: risk
});

// Drug Interaction Checker via RxNav API
// query should be a comma-separated list of drug names
const drugs = query.split(',').map(d => d.trim()).filter(Boolean);

try {
  // First, get RxCUI for each drug name
  const cuiResults = await Promise.all(drugs.map(async (drug) => {
    const url = `https://rxnav.nlm.nih.gov/REST/rxcui.json?name=${encodeURIComponent(drug)}&search=1`;
    const res = await $http.request({ method: 'GET', url });
    const data = res.body || res;
    const cui = data?.idGroup?.rxnormId?.[0] || null;
    return { drug, cui };
  }));

  const cuis = cuiResults.filter(r => r.cui).map(r => r.cui);

  if (cuis.length < 2) {
    return JSON.stringify({ drugs, note: 'Need at least 2 valid drugs for interaction check', cuiResults });
  }

  // Check interactions
  const intUrl = `https://rxnav.nlm.nih.gov/REST/interaction/list.json?rxcuis=${cuis.join('+')}` ;
  const intRes = await $http.request({ method: 'GET', url: intUrl });
  const intData = intRes.body || intRes;
  const interactions = intData?.fullInteractionTypeGroup || [];

  return JSON.stringify({ drugs, cuiResults, interactions });
} catch (e) {
  return JSON.stringify({ drugs, error: e.message });
}

// Clinical Guidelines RAG - queries Qdrant vector store
const queryText = typeof query === 'object' ? (query.query || query.input || JSON.stringify(query)) : String(query);

try {
  // First get embeddings from Ollama
  const embedResponse = await $http.request({
    method: 'POST',
    url: 'http://localhost:11434/api/embeddings',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'nomic-embed-text:latest', prompt: queryText })
  });
  const embedding = embedResponse.embedding;

  // Search Qdrant
  const searchResponse = await $http.request({
    method: 'POST',
    url: 'http://localhost:6333/collections/clinical_guidelines/points/search',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      vector: embedding,
      limit: 5,
      with_payload: true
    })
  });

  const results = searchResponse.result || [];
  if (results.length === 0) {
    return 'No clinical guidelines found for: ' + queryText;
  }

  const texts = results.map((r, i) => {
    const payload = r.payload || {};
    const text = payload.text || payload.content || payload.page_content || JSON.stringify(payload);
    return `[${i+1}] (score: ${r.score ? r.score.toFixed(3) : 'N/A'}) ${text}`;
  });

  return 'Clinical Guidelines for: ' + queryText + '\n\n' + texts.join('\n\n');
} catch (err) {
  return 'Clinical guidelines search unavailable. Proceeding with general knowledge. Error: ' + err.message;
}

// Similar Case Retrieval - queries Qdrant clinical_cases collection
const queryText = typeof query === 'object' ? (query.query || query.input || JSON.stringify(query)) : String(query);

try {
  // First get embeddings from Ollama
  const embedResponse = await $http.request({
    method: 'POST',
    url: 'http://localhost:11434/api/embeddings',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'nomic-embed-text:latest', prompt: queryText })
  });
  const embedding = embedResponse.embedding;

  // Search Qdrant clinical_cases collection
  const searchResponse = await $http.request({
    method: 'POST',
    url: 'http://localhost:6333/collections/clinical_cases/points/search',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      vector: embedding,
      limit: 3,
      with_payload: true
    })
  });

  const results = searchResponse.result || [];
  if (results.length === 0) {
    return 'No similar cases found for: ' + queryText;
  }

  const texts = results.map((r, i) => {
    const payload = r.payload || {};
    const text = payload.text || payload.content || payload.page_content || JSON.stringify(payload);
    return `[Case ${i+1}] (similarity: ${r.score ? r.score.toFixed(3) : 'N/A'}) ${text}`;
  });

  return 'Similar Clinical Cases for: ' + queryText + '\n\n' + texts.join('\n\n');
} catch (err) {
  return 'Similar case retrieval unavailable. Proceeding with clinical reasoning. Error: ' + err.message;
}
